require("fs"),async function(){console.log("Fetching products from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/products?pageSize=1000");if(!(await e.json()).documents)return void console.error("No products found");console.log("Warming up main home page...");try{await fetch("https://speedgifts.net/"),console.log("Main page warmed up successfully.")}catch(e){console.error("Failed to warm up main page:",e)}console.log("Warming up shop page...");try{await fetch("https://speedgifts.net/shop"),console.log("Shop page warmed up successfully.")}catch(e){console.error("Failed to warm up shop page:",e)}const o=10;console.log("Fetching categories from Firestore...");try{const e=await fetch("https://firestore.googleapis.com/v1/projects/speed-catalogue/databases/(default)/documents/artifacts/speed-catalogue/public/data/categories?pageSize=100"),t=await e.json();if(t.documents){const e=t.documents.map(e=>e.name.split("/").pop());console.log(`Fetched ${e.length} categories to warm up.`);let a=0,s=0;for(let t=0;t<e.length;t+=o){const c=e.slice(t,t+o).map(async e=>{const o=`https://speedgifts.net/shop?c=${encodeURIComponent(e)}`;try{(await fetch(o)).ok?a++:s++}catch(e){s++}});await Promise.all(c),await new Promise(e=>setTimeout(e,500)),console.log(`Category Progress: ${Math.min(t+o,e.length)} / ${e.length}`)}console.log(`Category Cache warming complete. Success: ${a}, Failed: ${s}`)}}catch(e){console.error("Failed to warm up categories:",e)}console.log("Manual Cache warming complete.")}catch(e){console.error("Error:",e)}}();